+        ByteVector vb = ByteVector.fromArray(B_SPECIES, bb, 0);
+        ByteVector vc = ByteVector.fromArray(B_SPECIES, bc, 0);
+        va.lanewise(VectorOperators.BITWISE_BLEND, vb, vc).intoArray(br, 0);
+    }
